import { useEffect, useState } from "react";
import { NavBarRecepcionar } from "./NavBarRecepcionar";
import pattern from "../slike/pattern4.jpg"

export function RezervacijeRecepcionar() {
    const [rezervacije, setRezervacije] = useState([]);
    const [filter, setFilter] = useState("ALL");
    const [izabranaRezervacija, setIzabranaRezervacija] = useState(null);
    const [showModal, setShowModal] = useState(false);

    const getCookie = (name) => {
        const match = document.cookie.match(new RegExp("(^| )" + name + "=([^;]+)"));
        return match ? match[2] : null;
    };
    const userId = getCookie("userId");

    useEffect(() => {
        fetch("http://localhost:8080/reservations/all")
            .then(res => res.json())
            .then(data => {
                if (data && data.data && data.data.values) {
                    setRezervacije(data.data.values);
                }
            })
            .catch(err => console.error("Greška pri učitavanju rezervacija:", err));
    }, []);

    const handleDelete = async (idRezervacija) => {
        if (!window.confirm("Da li ste sigurni da želite da obrišete ovu rezervaciju?")) return;

        try {
            const response = await fetch("http://localhost:8080/reservations/delete", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(idRezervacija),
            });
            const data = await response.json();
            if (response.ok) {
                alert("Rezervacija uspešno obrisana!");
                setRezervacije(prev => prev.filter(r => r.idRezervacija !== idRezervacija));
            } else {
                alert("Greška pri brisanju rezervacije: " + data.message);
            }
        } catch (err) {
            console.error(err);
        }
    };

    const handleEdit = (rezervacija) => {
        // Postavimo izabranu rezervaciju sa svim potrebnim vrednostima iz baze
        const datumPrijave = new Date(rezervacija.datumPrijave);
        const datumOdjave = new Date(rezervacija.datumOdjave);
        const brojDana = Math.max(1, Math.ceil((datumOdjave - datumPrijave) / (1000 * 60 * 60 * 24)));
        const ukupanIznos = (rezervacija.brojOsoba || 1) * (rezervacija.cenaPoOsobi || 0) * brojDana;

        setIzabranaRezervacija({
            ...rezervacija,
            brojOsoba: rezervacija.brojOsoba || 1,
            cenaPoOsobi: rezervacija.cenaPoOsobi || 0,
            ukupanIznos
        });
        setShowModal(true);
    };

    const handleSave = async () => {
        if (!izabranaRezervacija) return;
        try {
            const response = await fetch("http://localhost:8080/reservations/update", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(izabranaRezervacija),
            });
            if (response.ok) {
                alert("Rezervacija uspešno izmenjena!");
                setRezervacije(prev =>
                    prev.map(r => r.idRezervacija === izabranaRezervacija.idRezervacija ? izabranaRezervacija : r)
                );
                setShowModal(false);
            } else {
                alert("Greška pri čuvanju rezervacije.");
            }
        } catch (err) {
            console.error(err);
            alert("Greška pri čuvanju rezervacije.");
        }
    };

    const filtriraneRezervacije = filter === "ALL"
        ? rezervacije
        : rezervacije.filter(r => r.statusRezervacije === filter);

    const statusi = ["ALL", "CONFIRMED", "CHECKED_IN", "CHECKED_OUT", "CANCELLED"];

    return (
        <>
            <NavBarRecepcionar />
            <div style={{
                backgroundImage: `url(${pattern})`,
                backgroundSize: "cover",
                backgroundPosition: "center",
                minHeight: "100vh",
                padding: "40px",
            }}>
                <h2 style={{
                    textAlign: "center",
                    color: "white",
                    backgroundColor: "rgba(215, 96, 255, 0.6)",
                    padding: "15px 30px",
                    borderRadius: "10px",
                    display: "inline-block",
                }}>
                    Pregled rezervacija
                </h2>

                {/* Filter dugmad */}
                <div style={{ display: "flex", justifyContent: "center", marginBottom: "20px" }}>
                    {statusi.map(s => (
                        <button
                            key={s}
                            onClick={() => setFilter(s)}
                            style={{
                                margin: "0 8px",
                                padding: "8px 16px",
                                backgroundColor: filter === s ? "#ce7affff" : "#ffffffff",
                                color: filter === s ? "white" : "black",
                                border: "none",
                                borderRadius: "6px",
                                cursor: "pointer",
                            }}
                        >
                            {s === "ALL" ? "Sve" : s.replace("_", " ")}
                        </button>
                    ))}
                </div>

                {/* Kartice rezervacija */}
                <div style={{
                    display: "grid",
                    gridTemplateColumns: "repeat(auto-fill, minmax(300px, 1fr))",
                    gap: "20px",
                    padding: "0 20px",
                }}>
                    {filtriraneRezervacije.length > 0 ? (
                        filtriraneRezervacije.map(rez => (
                            <div key={rez.idRezervacija} style={{
                                backgroundColor: "#f7f9fc",
                                borderRadius: "10px",
                                padding: "20px",
                                boxShadow: "0px 2px 8px rgba(0,0,0,0.1)",
                            }}>
                                <h3>Rezervacija #{rez.idRezervacija}</h3>
                                <p><strong>Gost:</strong> {rez.gost?.ime} {rez.gost?.prezime}</p>
                                <p><strong>Soba:</strong> {rez.soba?.brojSobe}</p>
                                <p><strong>Datum prijave:</strong> {rez.datumPrijave}</p>
                                <p><strong>Datum odjave:</strong> {rez.datumOdjave}</p>
                                <p><strong>Status:</strong> {rez.statusRezervacije}</p>
                                <p><strong>Ukupan iznos:</strong> {rez.ukupanIznos} RSD</p>

                                <div style={{ display: "flex", justifyContent: "space-between", marginTop: "10px" }}>
                                    <button onClick={() => handleEdit(rez)} style={{
                                        backgroundColor: "#fff174ff",
                                        color: "black",
                                        border: "none",
                                        borderRadius: "6px",
                                        padding: "6px 12px",
                                        cursor: "pointer",
                                    }}>Izmeni</button>
                                    <button onClick={() => handleDelete(rez.idRezervacija)} style={{
                                        backgroundColor: "#fff174ff",
                                        color: "black",
                                        border: "none",
                                        borderRadius: "6px",
                                        padding: "6px 12px",
                                        cursor: "pointer",
                                    }}>Obriši</button>
                                </div>
                            </div>
                        ))
                    ) : (
                        <p style={{ textAlign: "center", width: "100%" }}>
                            Nema rezervacija za odabrani status.
                        </p>
                    )}
                </div>

                {/* MODAL ZA IZMENU REZERVACIJE */}
                {showModal && izabranaRezervacija && (
                    <div style={{
                        position: "fixed",
                        top: 0,
                        left: 0,
                        width: "100%",
                        height: "100%",
                        backgroundColor: "rgba(0,0,0,0.6)",
                        display: "flex",
                        justifyContent: "center",
                        alignItems: "center",
                    }}>
                        <div style={{ backgroundColor: "white", padding: "20px", borderRadius: "10px", width: "400px" }}>
                            <h3>Izmeni rezervaciju #{izabranaRezervacija.idRezervacija}</h3>

                            <label>Broj osoba:</label>
                            <input type="number" value={izabranaRezervacija.brojOsoba || 1} onChange={(e) => {
                                const noviBroj = parseInt(e.target.value) || 1;
                                const datumPrijave = new Date(izabranaRezervacija.datumPrijave);
                                const datumOdjave = new Date(izabranaRezervacija.datumOdjave);
                                const brojDana = Math.max(1, Math.ceil((datumOdjave - datumPrijave) / (1000 * 60 * 60 * 24)));
                                const cenaPoOsobi = izabranaRezervacija.cenaPoOsobi;
                                setIzabranaRezervacija({
                                    ...izabranaRezervacija,
                                    brojOsoba: noviBroj,
                                    ukupanIznos: noviBroj * cenaPoOsobi * brojDana
                                });
                            }} style={{ width: "100%", marginBottom: "10px" }} />

                            <label>Datum prijave:</label>
                            <input type="date" value={izabranaRezervacija.datumPrijave || ""} onChange={(e) => {
                                const noviDatum = e.target.value;
                                const datumPrijave = new Date(noviDatum);
                                const datumOdjave = new Date(izabranaRezervacija.datumOdjave);
                                const brojDana = Math.max(1, Math.ceil((datumOdjave - datumPrijave) / (1000 * 60 * 60 * 24)));
                                const cenaPoOsobi = izabranaRezervacija.cenaPoOsobi;
                                setIzabranaRezervacija({
                                    ...izabranaRezervacija,
                                    datumPrijave: noviDatum,
                                    ukupanIznos: izabranaRezervacija.brojOsoba * cenaPoOsobi * brojDana
                                });
                            }} style={{ width: "100%", marginBottom: "10px" }} />

                            <label>Datum odjave:</label>
                            <input type="date" value={izabranaRezervacija.datumOdjave || ""} onChange={(e) => {
                                const noviDatum = e.target.value;
                                const datumPrijave = new Date(izabranaRezervacija.datumPrijave);
                                const datumOdjave = new Date(noviDatum);
                                const brojDana = Math.max(1, Math.ceil((datumOdjave - datumPrijave) / (1000 * 60 * 60 * 24)));
                                const cenaPoOsobi = izabranaRezervacija.cenaPoOsobi;
                                setIzabranaRezervacija({
                                    ...izabranaRezervacija,
                                    datumOdjave: noviDatum,
                                    ukupanIznos: izabranaRezervacija.brojOsoba * cenaPoOsobi * brojDana
                                });
                            }} style={{ width: "100%", marginBottom: "10px" }} />

                            <label>Status rezervacije:</label>
                            <select value={izabranaRezervacija.statusRezervacije || "PENDING"} onChange={(e) =>
                                setIzabranaRezervacija({ ...izabranaRezervacija, statusRezervacije: e.target.value })
                            } style={{ width: "100%", marginBottom: "10px" }}>
                                <option value="PENDING">PENDING</option>
                                <option value="CONFIRMED">CONFIRMED</option>
                                <option value="CHECKED_IN">CHECKED_IN</option>
                                <option value="CHECKED_OUT">CHECKED_OUT</option>
                                <option value="CANCELLED">CANCELLED</option>
                            </select>

                            <div style={{ display: "flex", justifyContent: "flex-end" }}>
                                <button onClick={() => setShowModal(false)} style={{
                                    marginRight: "10px", backgroundColor: "gray", color: "white",
                                    border: "none", borderRadius: "5px", padding: "5px 10px"
                                }}>Otkaži</button>
                                <button onClick={handleSave} style={{
                                    backgroundColor: "purple", color: "white",
                                    border: "none", borderRadius: "5px", padding: "5px 10px"
                                }}>Sačuvaj</button>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </>
    );
}
